from kafka import KafkaConsumer
import json

class TransactionProcessor:
    def __init__(self, bootstrap_servers, topic):
        self.consumer = KafkaConsumer(
            topic,
            bootstrap_servers=bootstrap_servers,
            auto_offset_reset='earliest',
            group_id='transaction_group',
            value_deserializer=self.deserialize_message
        )

    def deserialize_message(self, message):
        return json.loads(message.decode('utf-8'))

    def process_transaction(self, transaction):
        # Implement your business logic here based on transaction content
        transaction_type = transaction.get("type")
        if transaction_type == "DEPOSIT":
            self.handle_deposit(transaction)
        elif transaction_type == "WITHDRAWAL":
            self.handle_withdrawal(transaction)
        # Add more handlers as needed

    def handle_deposit(self, transaction):
        # Handling deposit logic
        print(f"Processing deposit for account {transaction['account_id']} of amount {transaction['amount']}")

    def handle_withdrawal(self, transaction):
        # Handling withdrawal logic
        print(f"Processing withdrawal for account {transaction['account_id']} of amount {transaction['amount']}")

    def start_consuming(self):
        for message in self.consumer:
            transaction = message.value
            self.process_transaction(transaction)

if __name__ == "__main__":
    processor = TransactionProcessor(bootstrap_servers='localhost:9092', topic='financial_transactions')
    processor.start_consuming()